create extension if not exists "pgjwt" with schema "extensions";

create type "public"."document_status" as enum ('pending', 'processing', 'completed', 'failed');

create type "public"."job_status" as enum ('pending', 'processing', 'ready', 'matching', 'completed', 'failed');

create type "public"."match_decision" as enum ('rejected', 'accepted', 'pending');


  create table "public"."accepted_matches" (
    "id" bigint generated by default as identity not null,
    "term" text,
    "recommended_choice" uuid,
    "accepted_project" uuid,
    "user_id" uuid,
    "created_at" timestamp with time zone not null default now(),
    "intern_id" uuid
      );


alter table "public"."accepted_matches" enable row level security;


  create table "public"."jobs" (
    "id" uuid not null default gen_random_uuid(),
    "term" text,
    "status" public.job_status not null default 'pending'::public.job_status,
    "created_at" timestamp with time zone default now(),
    "rust_error" jsonb default '{"resumes": [], "projects": []}'::jsonb,
    "python_error" text
      );


alter table "public"."jobs" enable row level security;


  create table "public"."matches" (
    "id" uuid not null default gen_random_uuid(),
    "match_batch_id" uuid default gen_random_uuid(),
    "term" text,
    "intern_id" uuid,
    "project_id" uuid,
    "similarity_score" double precision,
    "created_at" timestamp with time zone not null,
    "decision" public.match_decision not null default 'pending'::public.match_decision
      );


alter table "public"."matches" enable row level security;


  create table "public"."project_uploads" (
    "id" uuid not null default gen_random_uuid(),
    "filename" text not null,
    "status" public.document_status not null default 'pending'::public.document_status,
    "error_message" text,
    "created_at" timestamp with time zone not null default now(),
    "user_id" uuid,
    "term" text,
    "job_id" uuid
      );


alter table "public"."project_uploads" enable row level security;


  create table "public"."projects" (
    "id" uuid not null default gen_random_uuid(),
    "upload_id" uuid,
    "title" text not null,
    "description" text,
    "requirements" text,
    "manager" text,
    "deadline" text,
    "priority" smallint default 0,
    "intern_cap" smallint default 1,
    "created_at" timestamp with time zone not null default now(),
    "term" text,
    "deliverable" text
      );


alter table "public"."projects" enable row level security;


  create table "public"."results" (
    "id" uuid not null default gen_random_uuid(),
    "term" text not null,
    "match_id" uuid not null,
    "intern_id" character varying,
    "Third_Score" real,
    "recommended_project_id" uuid default gen_random_uuid(),
    "status" character varying default 'pending'::character varying,
    "created_at" timestamp with time zone default now()
      );


alter table "public"."results" enable row level security;


  create table "public"."results_tab" (
    "id" uuid not null default gen_random_uuid(),
    "match_id" uuid not null,
    "term" text not null,
    "intern_id" uuid not null,
    "projects" jsonb not null,
    "recommended_project_id" uuid,
    "status" text not null default 'pending'::text,
    "created_at" timestamp with time zone default now()
      );


alter table "public"."results_tab" enable row level security;


  create table "public"."resume_uploads" (
    "id" uuid not null default gen_random_uuid(),
    "filename" text not null,
    "status" public.document_status not null default 'pending'::public.document_status,
    "error_message" text,
    "created_at" timestamp with time zone not null default now(),
    "user_id" uuid,
    "term" text,
    "zip_id" uuid,
    "job_id" uuid
      );


alter table "public"."resume_uploads" enable row level security;


  create table "public"."resumes" (
    "filename" text not null,
    "text" text,
    "structured" json,
    "id" uuid not null default gen_random_uuid(),
    "user_id" uuid,
    "created_at" timestamp with time zone default now(),
    "zip_id" uuid,
    "term" text,
    "upload_id" uuid
      );


alter table "public"."resumes" enable row level security;


  create table "public"."zip_archives" (
    "id" uuid not null default gen_random_uuid(),
    "filename" text not null,
    "status" public.document_status not null default 'pending'::public.document_status,
    "error_message" text,
    "created_at" timestamp with time zone default now(),
    "user_id" uuid,
    "term" text,
    "job_id" uuid
      );


alter table "public"."zip_archives" enable row level security;

