CREATE OR REPLACE FUNCTION public.handle_new_project_upload()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
declare
  job_id_val uuid;
BEGIN
  IF new.bucket_id = 'project-spreadsheets' and new.name NOT LIKE '%.emptyFolderPlaceholder' THEN
    begin
      job_id_val := (new.user_metadata ->> 'job_id')::uuid;
      if job_id_val is null then
         job_id_val := (new.metadata ->> 'job_id')::uuid;
      end if;
    exception when others then
      job_id_val := null;
    end;

    INSERT INTO public.project_uploads (filename, user_id, term, job_id)
    VALUES (
      new.name, 
      new.owner,
      CASE WHEN position('/' in new.name) > 0 THEN split_part(new.name, '/', 1) ELSE NULL END,
      job_id_val
    );
  END IF;
  RETURN new;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_resume_upload()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  zip_id_val uuid;
  job_id_val uuid;
begin
  -- Ignore folder placeholders created by Supabase Dashboard
  if new.bucket_id = 'resumes' and new.name NOT LIKE '%.emptyFolderPlaceholder' then
    -- Extract zip_id and job_id from metadata
    begin
      zip_id_val := (new.user_metadata ->> 'zip_id')::uuid;
      if zip_id_val is null then
         zip_id_val := (new.metadata ->> 'zip_id')::uuid;
      end if;
    exception when others then
      zip_id_val := null;
    end;

    begin
      job_id_val := (new.user_metadata ->> 'job_id')::uuid;
      if job_id_val is null then
         job_id_val := (new.metadata ->> 'job_id')::uuid;
      end if;
    exception when others then
      job_id_val := null;
    end;

    -- INSERT INTO resume_uploads
    insert into public.resume_uploads (
      user_id,
      filename,
      term,
      zip_id,
      job_id
    )
    values (
      new.owner,
      new.name,
      CASE WHEN position('/' in new.name) > 0 THEN split_part(new.name, '/', 1) ELSE NULL END,
      zip_id_val,
      job_id_val
    );
  end if;
  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_zip_upload()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
declare
  job_id_val uuid;
BEGIN
  IF new.bucket_id = 'zip-archives' and new.name NOT LIKE '%.emptyFolderPlaceholder' THEN
    begin
      job_id_val := (new.user_metadata ->> 'job_id')::uuid;
      if job_id_val is null then
         job_id_val := (new.metadata ->> 'job_id')::uuid;
      end if;
    exception when others then
      job_id_val := null;
    end;

    INSERT INTO public.zip_archives (filename, user_id, term, job_id)
    VALUES (
      new.name, 
      new.owner,
      CASE WHEN position('/' in new.name) > 0 THEN split_part(new.name, '/', 1) ELSE NULL END,
      job_id_val
    );
  END IF;
  RETURN new;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_project_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF old.bucket_id = 'project-spreadsheets' THEN
    DELETE FROM public.project_uploads
    WHERE filename = old.name;
  END IF;
  RETURN old;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_resume_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$begin
  -- 1. Filter: Only run this if the deleted file was in the 'resumes' bucket
  if old.bucket_id = 'resumes' then
  
    -- 2. Delete the row where the file path matches
    delete from public.resumes
    where filename = old.name;
    
  end if;

  return old;
end;$function$
;

CREATE OR REPLACE FUNCTION public.handle_zip_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- Check if the deleted file is in the 'zip-archives' bucket
  IF old.bucket_id = 'zip-archives' THEN
    DELETE FROM public.zip_archives
    WHERE filename = old.name;
  END IF;
  RETURN old;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notify_orchestrator_secure()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  secret text;
  token text;
  url text := TG_ARGV[0];
  headers jsonb;
  request_id bigint;
  payload jsonb;
  timeout_ms integer := 5000;
BEGIN
  -- Get Secret
  SELECT decrypted_secret INTO secret
  FROM vault.decrypted_secrets
  WHERE name = 'app_jwt_secret';

  IF secret IS NULL THEN
    RAISE EXCEPTION 'app_jwt_secret not found in vault';
  END IF;

  -- Sign Token (exp cast to bigint)
  token := sign(
    json_build_object(
      'role', 'service_role',
      'iss', 'supabase',
      'exp', (extract(epoch from now()) + 3600)::bigint,
      'sub', 'orchestrator'
    ),
    secret
  );

  -- Build Headers
  headers := jsonb_build_object(
    'Content-Type', 'application/json',
    'Authorization', 'Bearer ' || token
  );

  -- Build Payload
  payload := jsonb_build_object(
    'old_record', OLD,
    'record', NEW,
    'type', TG_OP,
    'table', TG_TABLE_NAME,
    'schema', TG_TABLE_SCHEMA
  );

  -- Send Request
  SELECT http_post INTO request_id
  FROM net.http_post(
    url,
    payload,
    '{}'::jsonb,
    headers,
    timeout_ms
  );

  RETURN NEW;
END;
$function$
;

